"use strict";(self.webpackChunkdocs_next=self.webpackChunkdocs_next||[]).push([[72400],{77973:e=>{e.exports=JSON.parse('{"tag":{"label":"sovereignty","permalink":"/docs-next/pr-preview/pr-375/docs/tags/sovereignty","allTagsPath":"/docs-next/pr-preview/pr-375/docs/tags","count":7,"items":[{"id":"blueprints/by-use-case/sovereignty/nextcloud/deploy-nextcloud-on-cce","title":"Deploy Nextcloud on CCE","description":"This guide walks through deploying a highly available Nextcloud setup on an Open Telekom Cloud Cloud Container Engine (CCE) cluster, using Object Storage Service (OBS) for file storage and Relational Database Service (RDS) for Nextcloud\'s database. We will use the Nextcloud Helm charts for that matter.","permalink":"/docs-next/pr-preview/pr-375/docs/blueprints/by-use-case/sovereignty/nextcloud/deploy-nextcloud-on-cce"},{"id":"blueprints/by-use-case/sovereignty/opendesk/deploy-opendesk-on-cce","title":"Deploy OpenDesk on CCE","description":"This blueprint showcases how to deploy a scalable, high-availability (HA) instance of OpenDesk on T Cloud Public. Unlike the evaluation environment demonstrated in a previous guide, this production setup externalizes some services such as databases, caches and object storage onto T Cloud Public Managed Services (RDS, DCS, OBS) and uses SFS Turbo for shared filesystem access.","permalink":"/docs-next/pr-preview/pr-375/docs/blueprints/by-use-case/sovereignty/opendesk/deploy-opendesk-on-cce"},{"id":"blueprints/by-use-case/sovereignty/opendesk/evaluate-opendesk-on-tcloud-public","title":"Evaluate OpenDesk on T Cloud Public","description":"This blueprint walks through deploying an OpenDesk instance for evaluation and testing purposes on T Cloud Public. All databases, caches, and object storage components are deployed as containers within the cluster.","permalink":"/docs-next/pr-preview/pr-375/docs/blueprints/by-use-case/sovereignty/opendesk/evaluate-opendesk-on-tcloud-public"},{"id":"blueprints/by-use-case/sovereignty/nextcloud/nextcloud","title":"Nextcloud","description":"Nextcloud is an open-source collaboration and file-sharing platform that organizations can deploy on-premises or in a private cloud. It combines secure file storage and synchronization with integrated groupware calendar, contacts and email, so teams can manage documents and communications from a single, self-hosted environment. By retaining full control over infrastructure and data location, Nextcloud helps maintain privacy, security and regulatory compliance.","permalink":"/docs-next/pr-preview/pr-375/docs/blueprints/by-use-case/sovereignty/nextcloud/"},{"id":"blueprints/by-use-case/sovereignty/opendesk/opendesk","title":"OpenDesk","description":"OpenDesk (branded as openDesk) is an open-source, sovereign digital workplace solution designed for public administration under the coordination of the German Federal Ministry of the Interior (BMI, Bundesministerium des Innern) and developed by the Centre for Digital Sovereignty of the Public Administration (ZenDiS GmbH, Zentrum f\xfcr Digitale Souver\xe4nit\xe4t der \xd6ffentlichen Verwaltung). It bundles established open-source applications into a single collaboration suite so that organisations can retain full control over their data, identities and infrastructure while avoiding dependence on large proprietary vendors.","permalink":"/docs-next/pr-preview/pr-375/docs/blueprints/by-use-case/sovereignty/opendesk/"},{"id":"blueprints/by-use-case/sovereignty/nextcloud/realtime-collaboration-with-collabora-online","title":"Real-Time Collaboration with Collabora Online","description":"Collabora Online is a web-based office suite built on LibreOffice and integrates seamlessly with Nextcloud to provide real-time collaborative document editing. It enables multiple users to simultaneously edit documents, spreadsheets, and presentations directly within the browser while maintaining full compatibility with Microsoft Office and OpenDocument formats. By deploying Collabora Online as a backend service, Nextcloud transforms from a simple file storage platform into a comprehensive collaborative workspace that rivals commercial solutions like Google Workspace or Microsoft Office 365, all while keeping your data under your complete control.","permalink":"/docs-next/pr-preview/pr-375/docs/blueprints/by-use-case/sovereignty/nextcloud/realtime-collaboration-with-collabora-online"},{"id":"blueprints/by-use-case/sovereignty/nextcloud/realtime-communication-with-nextcloud-talk","title":"Real-Time Communication with Nextcloud Talk","description":"Nextcloud Talk is a web and mobile-based communication app that provides real-time chat, video, and calls. As a privacy-respecting communication solution, it combines chat messaging, video conferencing, webinars, and screen sharing capabilities while maintaining complete control over your data and communications. By deploying Nextcloud Talk, organizations can establish a secure, GDPR-compliant alternative to other popular commercial platforms while ensuring that conversations, calls, and shared content remain under their direct control.","permalink":"/docs-next/pr-preview/pr-375/docs/blueprints/by-use-case/sovereignty/nextcloud/realtime-communication-with-nextcloud-talk"}],"unlisted":false}}')}}]);